import React from 'react'; // Importando o React para criar componentes
import { Link } from 'react-router-dom'; // Importando o Link para navegação entre as rotas
import './Navbar.css'; // Importando o arquivo de estilos CSS

const Navbar = () => {
  return (
    <nav className="navbar"> {/* Tag de navegação com a classe navbar */}
      <div className="navbar-left">
        <div className="navbar-logo">Prometheus</div> {/* Div para o logo da navbar */}
        {/* Menu principal da Navbar com submenus */}
        <ul className="navbar-links"> 
          <li className="dropdown"> {/* Item do menu que contém dropdown */}
            <Link to="/">Gestão</Link> {/* Link para a página Gestão */}
            {/* Submenu de Gestão */}
            <ul className="dropdown-menu"> 
              <li><Link to="/gestao/item1">Atendimento<href>'C:/Users/MatheusFernandes/AppData/Roaming/npm/juridico/src/pages/atendimento.js'</href></Link></li> {/* Link para Atendimento */}
              <li><Link to="/gestao/item2">Pessoa</Link></li> {/* Link para Pessoa */}
              <li><Link to="/gestao/item3">Workflow</Link></li> {/* Link para Workflow */}
              <li><Link to="/gestao/item4">Timesheet</Link></li> {/* Link para Timesheet */}
              <li><Link to="/gestao/item5">Relatórios</Link></li> {/* Link para Relatórios */}
            </ul>
          </li>
          <li className="dropdown">
            <Link to="/atividades">Atividades</Link> {/* Link para a página Atividades */}
            <ul className="dropdown-menu">
              <li><Link to="/atividades/item1">Lista de Atividades</Link></li> {/* Link para Lista de Atividades */}
              <li><Link to="/atividades/item2">Painel de Tarefas</Link></li> {/* Link para Painel de Tarefas */}
              <li><Link to="/atividades/item3">Kanban de Tarefas</Link></li> {/* Link para Kanban de Tarefas */}
              <li><Link to="/atividades/item4">Relatórios</Link></li> {/* Link para Relatórios */}
            </ul>
          </li>
          <li className="dropdown">
            <Link to="/processos">Processos</Link> {/* Link para a página Processos */}
            <ul className="dropdown-menu">
              <li><Link to="/processos/item1">Processos</Link></li> {/* Link para Processos */}
              <li><Link to="/processos/item2">Intimações</Link></li> {/* Link para Intimações */}
              <li><Link to="/processos/item3">Central de Captura</Link></li> {/* Link para Central de Captura */}
              <li><Link to="/processos/item4">Andamentos Processuais</Link></li> {/* Link para Andamentos Processuais */}
              <li><Link to="/processos/item5">Relatórios</Link></li> {/* Link para Relatórios */}
            </ul>
          </li>
          <li className="dropdown">
            <Link to="/financeiro">Financeiro</Link> {/* Link para a página Financeiro */}
            <ul className="dropdown-menu">
              <li><Link to="/financeiro/item1">Receitas e Despesas</Link></li> {/* Link para Receitas e Despesas */}
              <li><Link to="/financeiro/item2">Extrato de Conta</Link></li> {/* Link para Extrato de Conta */}
              <li><Link to="/financeiro/item3">Solicitações</Link></li> {/* Link para Solicitações */}
              <li><Link to="/financeiro/item4">Integração de Receitas</Link></li> {/* Link para Integração de Receitas */}
              <li><Link to="/financeiro/item5">Relatórios</Link></li> {/* Link para Relatórios */}
            </ul>
          </li>
          <li className="dropdown">
            <Link to="/documentos">Documentos</Link> {/* Link para a página Documentos */}
            <ul className="dropdown-menu">
              <li><Link to="/documentos/item1">Documentos</Link></li> {/* Link para Documentos */}
              <li><Link to="/documentos/item2">Modelos de Documentos</Link></li> {/* Link para Modelos de Documentos */}
            </ul>
          </li>
          <li className="dropdown">
            <Link to="/extensoes">Extensões</Link> {/* Link para a página Extensões */}
            <ul className="dropdown-menu">
              <li><Link to="/extensoes/item1">Conexões</Link></li> {/* Link para Conexões */}
              <li><Link to="/extensoes/item2">Relatórios</Link></li> {/* Link para Relatórios */}
            </ul>
          </li>
        </ul>
      </div>

      {/* Seção da Barra de Pesquisa e Ícones ao lado direito */}
      <div className="navbar-right">
        {/* Barra de Pesquisa */}
        <div className="navbar-search">
          <input type="text" placeholder="Pesquisar..." /> {/* Input da barra de pesquisa */}
        </div>
        
        <div className="navbar-icons">
          {/* Notificações */}
          <div className="dropdown">
            <button className="icon-button">🔔</button> {/* Ícone de notificações */}
            <ul className="dropdown-menu">
              <li><Link to="/notificacao/item1">Notificação 1</Link></li> {/* Link para Notificação 1 */}
              <li><Link to="/notificacao/item2">Notificação 2</Link></li> {/* Link para Notificação 2 */}
              <li><Link to="/notificacao/item3">Notificação 3</Link></li> {/* Link para Notificação 3 */}
              <li><Link to="/notificacao/item4">Notificação 4</Link></li> {/* Link para Notificação 4 */}
            </ul>
          </div>

          {/* Configurações */}
          <div className="dropdown">
            <button className="icon-button">⚙️</button> {/* Ícone de configurações */}
            <ul className="dropdown-menu">
              <li><Link to="/configuracoes/item1">Perfil</Link></li> {/* Link para o Perfil */}
              <li><Link to="/configuracoes/item2">Preferências</Link></li> {/* Link para Preferências */}
              <li><Link to="/configuracoes/item3">Sair</Link></li> {/* Link para sair */}
            </ul>
          </div>

          {/* Ajuda */}
          <div className="dropdown">
            <button className="icon-button">❓</button> {/* Ícone de ajuda */}
            <ul className="dropdown-menu">
              <li><Link to="/ajuda/item1">FAQ</Link></li> {/* Link para FAQ */}
              <li><Link to="/ajuda/item2">Contrato</Link></li> {/* Link para Contrato */}
              <li><Link to="/ajuda/item3">Suporte</Link></li> {/* Link para Suporte */}
            </ul>
          </div>

          {/* Área do Usuário */}
          <div className="dropdown">
            <button className="icon-button">👤</button> {/* Ícone da área do usuário */}
            <ul className="dropdown-menu">
              <li><Link to="/area_do_usuario/item1">Meu Perfil</Link></li> {/* Link para Meu Perfil */}
              <li><Link to="/area_do_usuario/item2">Configurações</Link></li> {/* Link para Configurações */}
              <li><Link to="/area_do_usuario/item3">Logout</Link></li> {/* Link para Logout */}
            </ul>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar; // Exporta o componente Navbar para ser usado em outros lugares
